import prometheus_client
import time
import random
from flask import Flask, request

app = Flask(__name__)

# Create a Prometheus registry
REGISTRY = prometheus_client.CollectorRegistry()

# Initialize a dictionary to store Gauge metrics for each user-path combination
# Key: (user_id, request_path), Value: Gauge metric
user_path_gauges = {}

# Expose metrics endpoint
@app.route('/metrics')
def metrics():
    return prometheus_client.generate_latest(REGISTRY)

# Simulate an HTTP request endpoint
@app.route('/<path:subpath>')
def handle_request(subpath):
    user_id = request.args.get('user_id', f'user_{random.randint(1, 10)}')
    session_id = request.args.get('session_id', f'session_{random.randint(100, 999)}')
    full_request_path = request.path

    # Create a unique key for the user-path combination
    metric_key = (user_id, full_request_path)

    # If the Gauge metric for this combination doesn't exist, create it
    if metric_key not in user_path_gauges:
        # Sanitize metric name for Prometheus
        metric_name = f"http_request_active_user_{user_id.replace('-', '_')}_path_{full_request_path.replace('/', '_').replace('.', '_').strip('_')}"
        metric_description = f"Active HTTP requests for user_id='{user_id}' and path='{full_request_path}'"
        
        user_path_gauges[metric_key] = prometheus_client.Gauge(
            metric_name,
            metric_description,
            labelnames=['user_id', 'session_id', 'full_request_path'],
            registry=REGISTRY
        )

    # Get the specific Gauge for this user-path combination
    gauge = user_path_gauges[metric_key]

    # Increment the gauge for the current request
    gauge.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).inc()

    # Simulate request processing time
    time.sleep(random.uniform(0.1, 0.5))

    # Decrement the gauge after the request is complete
    gauge.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).dec()

    return f"Request handled for user {user_id} on path {full_request_path}"

if __name__ == '__main__':
    # Start up the Prometheus client
    prometheus_client.start_http_server(8000, registry=REGISTRY)
    print("Prometheus metrics available on port 8000")

    # Run the Flask app
    app.run(debug=False, port=5000)